// piece_table.h - Piece table data structure for efficient text editing
//
// A piece table represents text as a sequence of "pieces" that reference
// either the original immutable buffer or an append-only buffer for edits.
// This provides O(1) undo via snapshot, efficient large file handling,
// and memory-mapped file support.

#pragma once

#include <vector>
#include <cstddef>
#include <cstdint>

namespace CodeEditor {

// ============================================================================
// Piece Table Data Structures
// ============================================================================

enum class PieceSource : uint8_t {
    Original,   // References the original (immutable) buffer
    Append      // References the append buffer (insertions)
};

struct Piece {
    PieceSource source;
    size_t offset;      // Byte offset into source buffer
    size_t length;      // Length in bytes
};

// ============================================================================
// PieceTable Class
// ============================================================================

class PieceTable {
public:
    static constexpr size_t MAX_UNDO_LEVELS = 100;

    PieceTable();
    ~PieceTable();

    // Initialization
    // Copies the input string into an owned buffer
    void init_from_string(const char* utf8_text, size_t len);

    // Initialize from external buffer (zero-copy, caller must keep alive)
    void init_from_buffer(const char* buffer, size_t len, bool take_ownership);

    // Clear all content
    void clear();

    // ========================================================================
    // Core Operations
    // ========================================================================

    // Insert text at byte position
    // Returns false if position is out of bounds
    bool insert(size_t pos, const char* text, size_t len);

    // Delete range starting at pos with given length
    // Returns false if range is out of bounds
    bool delete_range(size_t pos, size_t len);

    // Extract text into buffer
    // Returns number of bytes written (may be less than len if buf_len too small)
    size_t get_text(size_t pos, char* buf, size_t buf_len) const;

    // Get total document length in bytes
    size_t total_length() const { return total_len; }

    // Check if document is empty
    bool empty() const { return total_len == 0; }

    // ========================================================================
    // Line Operations (for LineIndex integration)
    // ========================================================================

    // Count total lines (number of '\n' + 1)
    size_t count_lines() const;

    // Get byte offset of line start (0-indexed line number)
    // Returns total_length() if line_num >= line count
    size_t get_line_start(size_t line_num) const;

    // Get line length including newline (if present)
    size_t get_line_length(size_t line_num) const;

    // Find line number containing byte offset
    size_t byte_to_line(size_t byte_offset) const;

    // ========================================================================
    // Undo/Redo
    // ========================================================================

    // Push current state to undo stack (with cursor and selection for restoration)
    void push_undo(size_t cursor_pos = 0, size_t selection_start = 0, size_t selection_end = 0);

    // Undo last change, returns cursor position to restore (or 0 if nothing to undo)
    // current_cursor_pos and selection are stored for redo restoration
    // out_selection_start and out_selection_end are set to the restored selection
    size_t undo(size_t current_cursor_pos = 0, size_t current_sel_start = 0, size_t current_sel_end = 0,
                size_t* out_selection_start = nullptr, size_t* out_selection_end = nullptr);

    // Redo last undone change, returns cursor position to restore (or 0 if nothing to redo)
    // out_selection_start and out_selection_end are set to the restored selection
    size_t redo(size_t* out_selection_start = nullptr, size_t* out_selection_end = nullptr);

    bool can_undo() const { return undo_pos > 0; }
    bool can_redo() const { return (undo_pos + 1) < undo_stack.size(); }
    size_t undo_position() const { return undo_pos; }

    // Clear undo history (e.g., after save)
    void clear_undo_history();

    // ========================================================================
    // Debug/Inspection
    // ========================================================================

    size_t piece_count() const { return pieces.size(); }
    size_t append_buffer_size() const { return append_buf.size(); }

private:
    // Find piece containing byte position
    // Returns piece index and offset within that piece
    struct PieceLocation {
        size_t piece_index;
        size_t offset_in_piece;
    };
    PieceLocation find_piece(size_t pos) const;

    // Get pointer to data for a piece
    const char* piece_data(const Piece& p) const;

    // Recalculate total length from pieces
    void recalc_total_length();

    // Original buffer (immutable after init)
    char* original;
    size_t original_len;
    bool owns_original;

    // Append buffer (all insertions go here)
    std::vector<char> append_buf;

    // The piece table itself
    std::vector<Piece> pieces;

    // Cached total length
    size_t total_len;

    // Undo/redo state
    struct Snapshot {
        std::vector<Piece> pieces;
        size_t append_buf_size;     // Size of append_buf at snapshot time
        size_t total_len;
        size_t cursor_pos;          // Cursor position for restoration on undo/redo
        size_t selection_start;     // Selection range for restoration
        size_t selection_end;
    };
    std::vector<Snapshot> undo_stack;
    size_t undo_pos;    // Current position in undo stack (0 = no undo available)
};

} // namespace CodeEditor
